```typescript
export type TrialPhaseEvent =
  | { type: "TrialPhaseOpened"; trialId: string; phase: string; at: string }
  | { type: "TrialPhaseAdvanced"; trialId: string; phase: string; at: string }
  | { type: "TrialPhaseClosed"; trialId: string; at: string }
  | { type: "TrialPhaseNoteAttached"; trialId: string; note: string };

export type TrialPhaseView = Readonly<{
  byTrial: Readonly<Record<string, { phase: string; updatedAt: string } | undefined>>;
  openCount: number;
}>;

export const emptyView: TrialPhaseView = { byTrial: {}, openCount: 0 };

export function project(view: TrialPhaseView, event: TrialPhaseEvent): TrialPhaseView {
  switch (event.type) {
    case "TrialPhaseOpened":
      return {
        byTrial: { ...view.byTrial, [event.trialId]: { phase: event.phase, updatedAt: event.at } },
        openCount: view.openCount + 1,
      };
    case "TrialPhaseAdvanced":
      return {
        ...view,
        byTrial: { ...view.byTrial, [event.trialId]: { phase: event.phase, updatedAt: event.at } },
      };
    case "TrialPhaseClosed": {
      const next = { ...view.byTrial };
      delete next[event.trialId];
      return { byTrial: next, openCount: Math.max(0, view.openCount - 1) };
    }
    case "TrialPhaseNoteAttached":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function aggregateStream(events: TrialPhaseView[] extends never ? never : TrialPhaseEvent[]): TrialPhaseView {
  return events.reduce<TrialPhaseView>(project, emptyView);
}
