```typescript
export type TreatmentEvent =
  | { type: "TreatmentAssigned"; treatmentId: string; subjectId: string }
  | { type: "TreatmentCompleted"; treatmentId: string; subjectId: string }
  | { type: "TreatmentDroppedOut"; treatmentId: string; subjectId: string; reason: string }
  | { type: "TreatmentLabelChanged"; treatmentId: string; label: string };

export type TreatmentView = Readonly<{
  byTreatment: Readonly<
    Record<string, { assigned: number; completed: number; dropouts: number } | undefined>
  >;
}>;

export const emptyView: TreatmentView = { byTreatment: {} };

function entry(view: TreatmentView, id: string): { assigned: number; completed: number; dropouts: number } {
  return view.byTreatment[id] ?? { assigned: 0, completed: 0, dropouts: 0 };
}

export function project(view: TreatmentView, event: TreatmentEvent): TreatmentView {
  switch (event.type) {
    case "TreatmentAssigned": {
      const e = entry(view, event.treatmentId);
      return { byTreatment: { ...view.byTreatment, [event.treatmentId]: { ...e, assigned: e.assigned + 1 } } };
    }
    case "TreatmentCompleted": {
      const e = entry(view, event.treatmentId);
      return { byTreatment: { ...view.byTreatment, [event.treatmentId]: { ...e, completed: e.completed + 1 } } };
    }
    case "TreatmentDroppedOut": {
      const e = entry(view, event.treatmentId);
      return { byTreatment: { ...view.byTreatment, [event.treatmentId]: { ...e, dropouts: e.dropouts + 1 } } };
    }
    case "TreatmentLabelChanged":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
