```typescript
export type ExperimentV1 = { id: string; name: string };
export type ExperimentV2 = { id: string; name: string; hypothesis: string };
export type ExperimentV3 = { id: string; name: string; hypothesis: string; verdict: "pending" | "win" | "loss" };

export type CurrentExperiment = ExperimentV3;
export const CURRENT_VERSION = 3;

export type Snapshot<S> = { version: number; state: S };

export function v1Tov2(state: ExperimentV1): ExperimentV2 {
  return { ...state, hypothesis: "" };
}

export function v2Tov3(state: ExperimentV2): ExperimentV3 {
  return { ...state, verdict: "pending" };
}

function isV1(s: unknown): s is ExperimentV1 {
  return typeof s === "object" && s !== null && "id" in s && "name" in s;
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentExperiment> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    if (!isV1(state)) throw new Error("INVALID_V1_SNAPSHOT");
    state = v1Tov2(state);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as ExperimentV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${version}`);
  return { version: CURRENT_VERSION, state: state as CurrentExperiment };
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
