export type FeatureFlagV1 = { id: string; key: string };
export type FeatureFlagV2 = { id: string; key: string; enabled: boolean };
export type FeatureFlagV3 = { id: string; key: string; enabled: boolean; owner: string };

export type CurrentFeatureFlag = FeatureFlagV3;
export const CURRENT_VERSION = 3;

