export function v1Tov2(state: FeatureFlagV1): FeatureFlagV2 {
  return { ...state, enabled: false };
}

export function v2Tov3(state: FeatureFlagV2): FeatureFlagV3 {
  return { ...state, owner: "unknown" };
}

export function loadFeatureFlag(snap: Snapshot<unknown>): Snapshot<CurrentFeatureFlag> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as FeatureFlagV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as FeatureFlagV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNKNOWN_VERSION_${version}`);
  return { version, state: state as CurrentFeatureFlag };
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
