import { Effect } from "effect";

export type RolloutV1 = { id: string; stage: number };
export type RolloutV2 = { id: string; stage: number; total: number };
export type RolloutV3 = { id: string; stage: number; total: number; halted: boolean };

export type CurrentRollout = RolloutV3;
export const CURRENT_VERSION = 3;

export type Snapshot<S> = { version: number; state: S };

export function v1Tov2(s: RolloutV1): RolloutV2 {
  return { ...s, total: 4 };
