export function v2Tov3(s: RolloutV2): RolloutV3 {
  return { ...s, halted: false };
}

export class UpgradeError {
  readonly _tag = "UpgradeError";
  constructor(readonly version: number) {}
}

export function upgradeSnapshot(
  snap: Snapshot<unknown>,
): Effect.Effect<Snapshot<CurrentRollout>, UpgradeError> {
  return Effect.gen(function* () {
    let version = snap.version;
    let state: unknown = snap.state;
    if (version === 1) {
      state = v1Tov2(state as RolloutV1);
      version = 2;
    }
    if (version === 2) {
      state = v2Tov3(state as RolloutV2);
      version = 3;
    }
    if (version !== CURRENT_VERSION) {
      return yield* Effect.fail(new UpgradeError(version));
    }
    return { version, state: state as CurrentRollout };
  });
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
