  byTrial: Record<string, { phase: string } | undefined>;
}

export function project(view: TrialPhaseView, event: TrialPhaseEvent): TrialPhaseView {
  switch (event.type) {
    case "TrialPhaseOpened":
    case "TrialPhaseAdvanced":
      return { byTrial: { ...view.byTrial, [event.trialId]: { phase: event.phase } } };
    case "TrialPhaseClosed": {
      const next = { ...view.byTrial };
      delete next[event.trialId];
      return { byTrial: next };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

