  name: string,
  feed: EventFeed<TrialPhaseEvent>,
  checkpoints: CheckpointStore,
  apply: (event: TrialPhaseEvent) => Promise<void>,
): Promise<void> {
  const last = (await checkpoints.read(name)) ?? 0n;
  for await (const envelope of feed.subscribe(last)) {
    await apply(envelope.event);
    await checkpoints.write(name, envelope.position);
  }
}
