  | { type: "ExperimentDesigned"; version: 2; id: string; hypothesis: string; ownerId: string }
  | { type: "ExperimentLaunched"; version: 1; at: string };

export class UnknownEventError extends Error {
  constructor(public readonly raw: unknown) {
    super("UNKNOWN_EVENT");
    this.name = "UnknownEventError";
  }
}

function isRaw(value: unknown): value is RawExperimentEvent {
  return typeof value === "object" && value !== null && "type" in value && "version" in value;
}

export function upcast(raw: unknown): CurrentExperimentEvent {
  if (!isRaw(raw)) throw new UnknownEventError(raw);
  switch (raw.type) {
    case "ExperimentDesigned":
      if (raw.version === 1) return { type: "ExperimentDesigned", id: raw.id, hypothesis: raw.hypothesis, ownerId: "legacy" };
      if (raw.version === 2) return { type: "ExperimentDesigned", id: raw.id, hypothesis: raw.hypothesis, ownerId: raw.ownerId };
      throw new UnknownEventError(raw);
    case "ExperimentLaunched":
      if (raw.version === 1) return { type: "ExperimentLaunched", at: raw.at };
      throw new UnknownEventError(raw);
    default: {
      const _never: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
