export type RolloutEvent =
  | { type: "RolloutPlanned"; id: string; total: number }
  | { type: "RolloutAdvanced"; stage: number }
  | { type: "RolloutHalted" };

export interface EventRecord<E> { event: E; revision: bigint; }

export interface EventStore {
  readStream<E>(stream: string, opts: { from: bigint; batchSize: number }): Promise<EventRecord<E>[]>;
}

export interface ReadModelView {
  byRollout: Record<string, { stage: number; total: number; halted: boolean } | undefined>;
}

export function project(view: ReadModelView, event: RolloutEvent): ReadModelView {
  switch (event.type) {
    case "RolloutPlanned":
      return { byRollout: { ...view.byRollout, [event.id]: { stage: 0, total: event.total, halted: false } } };
    case "RolloutAdvanced":
      return view;
    case "RolloutHalted":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function rebuild(opts: {
  stream: string;
  from: bigint;
  batchSize: number;
  store: EventStore;
  persist: (view: ReadModelView, cursor: bigint) => Promise<void>;
}): Promise<void> {
  let cursor = opts.from;
  let view: ReadModelView = { byRollout: {} };
  for (;;) {
    const batch = await opts.store.readStream<RolloutEvent>(opts.stream, { from: cursor, batchSize: opts.batchSize });
    if (batch.length === 0) break;
    for (const rec of batch) {
      view = project(view, rec.event);
      cursor = rec.revision + 1n;
    }
    await opts.persist(view, cursor);
  }
}
