```typescript
export type ExperimentCommand =
  | { type: "design"; id: string; hypothesis: string }
  | { type: "launch"; at: string };

export type ExperimentEvent =
  | { type: "ExperimentDesigned"; id: string; hypothesis: string }
  | { type: "ExperimentLaunched"; at: string };

export type WriteState =
  | { status: "none" }
  | { status: "designed"; id: string }
  | { status: "running"; id: string };

export interface ExperimentReadView {
  id: string;
  running: boolean;
}

export const initialState: WriteState = { status: "none" };

export function evolve(state: WriteState, event: ExperimentEvent): WriteState {
  switch (event.type) {
    case "ExperimentDesigned":
      return { status: "designed", id: event.id };
    case "ExperimentLaunched":
      if (state.status !== "designed") return state;
      return { status: "running", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(cmd: ExperimentCommand, state: WriteState): ExperimentEvent[] {
  switch (cmd.type) {
    case "design":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ExperimentDesigned", id: cmd.id, hypothesis: cmd.hypothesis }];
    case "launch":
      if (state.status !== "designed") throw new Error("NOT_DESIGNED");
      return [{ type: "ExperimentLaunched", at: cmd.at }];
    default: {
      const _never: never = cmd;
      throw new Error("UNKNOWN");
    }
  }
}

export interface AppendOptions { expectedRevision: bigint | "no_stream" | "any"; }
export interface EventStore {
  readStream<E>(stream: string): Promise<{ event: E; revision: bigint }[]>;
  appendToStream<E>(stream: string, events: E[], opts: AppendOptions): Promise<void>;
}

export interface ReadStore {
  getExperiment(id: string): Promise<ExperimentReadView | null>;
}

// The read store is eventually consistent with the event store: a successful
// handleCommand does not guarantee that a subsequent queryView reflects it yet.

export async function handleCommand(
  cmd: ExperimentCommand,
  deps: { stream: string; store: EventStore },
): Promise<void> {
  const records = await deps.store.readStream<ExperimentEvent>(deps.stream);
  const state = records.reduce<WriteState>((s, r) => evolve(s, r.event), initialState);
  const events = decide(cmd, state);
  const expected: AppendOptions["expectedRevision"] =
    records.length === 0 ? "no_stream" : records[records.length - 1].revision;
  await deps.store.appendToStream<ExperimentEvent>(deps.stream, events, { expectedRevision: expected });
}

export async function queryView(id: string, read: ReadStore): Promise<ExperimentReadView | null> {
  return read.getExperiment(id);
}
```

