export type FeatureFlagState =
  | { status: "missing" }
  | { status: "disabled"; id: string }
  | { status: "enabled"; id: string };

export type FeatureFlagCommand =
  | { type: "create"; id: string; key: string }
  | { type: "enable" }
  | { type: "disable" };

export type FeatureFlagEvent =
  | { type: "FeatureFlagCreated"; id: string; key: string }
  | { type: "FeatureFlagEnabled" }
  | { type: "FeatureFlagDisabled" };

export class FeatureFlagError extends Error {
  constructor(code: string) { super(code); this.name = "FeatureFlagError"; }
}

export function decide(command: FeatureFlagCommand, state: FeatureFlagState): FeatureFlagEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "missing") throw new FeatureFlagError("EXISTS");
      return [{ type: "FeatureFlagCreated", id: command.id, key: command.key }];
    case "enable":
      if (state.status === "enabled") throw new FeatureFlagError("ALREADY_ENABLED");
      if (state.status !== "disabled") throw new FeatureFlagError("NOT_CREATED");
      return [{ type: "FeatureFlagEnabled" }];
    case "disable":
      if (state.status !== "enabled") throw new FeatureFlagError("NOT_ENABLED");
      return [{ type: "FeatureFlagDisabled" }];
    default: {
      const _never: never = command;
      throw new FeatureFlagError("UNKNOWN_COMMAND");
    }
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}
```

A GuardrailMetric evolve reducer stays pure: it turns an append-only stream of observations into a running summary (count, sum, last-breach). Because it is a plain function over a discriminated union, the same stream always rebuilds the same stats, which is what makes event-sourced metrics reproducible.

```typescript
export type GuardrailMetricEvent =
  | { type: "GuardrailMetricInitialized"; metricId: string; threshold: number }
  | { type: "GuardrailMetricSampled"; value: number }
  | { type: "GuardrailMetricBreached"; at: string };

export type GuardrailMetricState = Readonly<{
  metricId?: string;
  threshold: number;
  count: number;
  sum: number;
  lastBreachAt?: string;
}>;

export const initialState: GuardrailMetricState = { threshold: Number.POSITIVE_INFINITY, count: 0, sum: 0 };

export function evolve(state: GuardrailMetricState, event: GuardrailMetricEvent): GuardrailMetricState {
  switch (event.type) {
    case "GuardrailMetricInitialized":
      return { ...state, metricId: event.metricId, threshold: event.threshold };
    case "GuardrailMetricSampled":
      return { ...state, count: state.count + 1, sum: state.sum + event.value };
    case "GuardrailMetricBreached":
      return { ...state, lastBreachAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function aggregateStream(events: GuardrailMetricEvent[]): GuardrailMetricState {
  return events.reduce<GuardrailMetricState>(evolve, initialState);
}
```

```typescript
export type SignificanceCheckEvent =
  | { type: "SignificanceCheckStarted"; id: string; alpha: number }
  | { type: "SignificanceCheckPValueObserved"; pValue: number }
  | { type: "SignificanceCheckCompleted"; verdict: "significant" | "not_significant" };

export interface EventEnvelope<E> {
  event: E;
  revision: bigint;
}

export interface EventStore {
  readStream<E>(stream: string, opts: { fromRevision?: bigint }): AsyncIterable<EventEnvelope<E>>;
}

export async function readStreamIntoArray(
  store: EventStore,
  stream: string,
  fromRevision?: bigint,
): Promise<EventEnvelope<SignificanceCheckEvent>[]> {
  const out: EventEnvelope<SignificanceCheckEvent>[] = [];
  for await (const envelope of store.readStream<SignificanceCheckEvent>(stream, { fromRevision })) {
    out.push(envelope);
  }
  return out;
}

export function summarise(events: SignificanceCheckEvent[]): {
  alpha: number;
  pValues: number[];
  verdict: "significant" | "not_significant" | "pending";
} {
  let alpha = 0;
  const pValues: number[] = [];
  let verdict: "significant" | "not_significant" | "pending" = "pending";
  for (const event of events) {
    switch (event.type) {
      case "SignificanceCheckStarted":
        alpha = event.alpha;
        break;
      case "SignificanceCheckPValueObserved":
        pValues.push(event.pValue);
        break;
      case "SignificanceCheckCompleted":
        verdict = event.verdict;
        break;
      default: {
        const _never: never = event;
      }
    }
  }
  return { alpha, pValues, verdict };
}
